// // This module is designed to be a 4-bit synchronous down-counter with asynchronous reset.
module up_counter(
    input clk,
    input reset,
    output reg [3:0] q
    );

    always @(posedge clk)
    begin
        if (reset)
            q <= 4'b0000;
        else
            q <= q + 1;
    end

endmodule
